struct Node { value: i32, left: Option<Box<Node>>, right: Option<Box<Node>> }
fn insert(node: Option<Box<Node>>, value: i32) -> Option<Box<Node>> {
    match node {
        None => Some(Box::new(Node { value, left: None, right: None })),
        Some(mut n) => {
            if value < n.value { n.left = insert(n.left, value); }
            else if value > n.value { n.right = insert(n.right, value); }
            Some(n)
        }
    }
}

